const $ = require('jquery');
const _ = require('lodash');

const CONSOLE = require('./console');
const UTIL = require('./util');

const JQ_BROWSER = require('jquery.browser');

// 컨텐츠 타입
const CONTENT_TYPE = {
    "csv": 'application/csv',
    "excel": 'application/vnd.ms-excel',
    "word": 'application/vnd.ms-word'
};

// 파일 확장자
const FILE_EXT = {
    "csv": 'csv',
    "excel": 'xls'
};

const EXPORTER = {
    /**
     * @memberof BXUI.Exporter
     */
    "exportCSV": _exportCSV,
    /**
     * @memberof BXUI.Exporter
     */
    "exportExcel": _exportExcel
};

/**
 * CSV 파일을 export 한다.
 *
 * @param {Object} v - json 데이터
 * @param {String} fileName - 파일명
 *
 * @return {object} BXUI.Exporter 객체
 */
function _exportCSV(v = {}, fileName = ''){

    if (_.isPlainObject(v)){
        CONSOLE.prop.throw('BXUI.Exporter.exportCSV', 'v', 'type');
    }

    if (!_.isString(fileName)){
        CONSOLE.prop.throw('BXUI.Exporter.exportCSV', 'fileName', 'type');
    }

    fileName = fileName || 'unknown';

    v = UTIL.JSONToCSV(v);

    _saveAs(v, fileName, 'csv');

    return this;
}

/**
 * Excel 파일을 export 한다.
 *
 * @param {Object} $table - table 엘리먼트
 * @param {String} fileName - 파일명
 * @param {String} workSheetName - 워크시트명
 *
 * @return {object} BXUI.Exporter 객체
 */
function _exportExcel($table = null, fileName = '', workSheetName = ''){

    if (!_.isFunction($table.get) || !_.isElement($table.get(0))){
        CONSOLE.prop.throw('BXUI.Exporter.exportExcel', '$table', 'type');
    }

    if (!_.isString(fileName)){
        CONSOLE.prop.throw('BXUI.Exporter.exportExcel', 'fileName', 'type');
    }

    if (!_.isString(workSheetName)){
        CONSOLE.prop.throw('BXUI.Exporter.exportExcel', 'workSheetName', 'type');
    }

    fileName = fileName || 'unknown';

    _saveAs(_transformTemplate($table.get(0).outerHTML, workSheetName), fileName, 'excel');

    return this;
}

/**
 * 파일을 저장한다.
 *
 * @param {Object} fileData - 파일 데이터
 * @param {String} fileName - 파일명
 * @param {String} type - 파일 타입
 *
 * @return {object} BXUI.Exporter 객체
 */
function _saveAs(fileData = '', fileName = '', type = 'csv'){

    if (!_.isString(fileData) || !_.trim(fileData).length){
        CONSOLE.prop.throw('BXUI.Exporter.saveAs', 'fileData', 'all');
    }

    if (!_.isString(fileName)){
        CONSOLE.prop.throw('BXUI.Exporter.saveAs', 'fileName', 'all');
    }

    if (!_.isString(type) || !CONTENT_TYPE[type]){
        CONSOLE.prop.throw('BXUI.Exporter.saveAs', 'type', 'type');
    }

    fileName = fileName || 'unknown';

    let contentType = CONTENT_TYPE[type];

    let $body = $(document.body);
    let $ifm = $(document.createElement('iframe'));

    let blob = null;


    // 파일 저장에 대한 브라우저 지원 여부
    // https://github.com/eligrey/FileSaver.js/#supported-browsers

    UTIL.isSupportedDataURI().then((isSupportedDataURI) => {

        if (window.navigator.msSaveBlob){
            _saveAsWithMsSaveBlob();
        }
        else if (window.URL){

            // safari 10.1.x 버전 이하일 경우에는, anchor 태그의 `download` 속성이 완벽히 지원하지않는 이슈가 존재한다.
            if (JQ_BROWSER.safari && UTIL.isBelowSafariVersion(10, 1)){
                _saveAsWithDataURI();
            }
            else{
                _saveAsWithURL();
            }
        }
        else if (isSupportedDataURI){

            // ie8 ~ ie9 브라우저에서는 `data uri scheme`을 일부 contentType(text/plain 등)에 한해서만 지원하는 이슈가 존재한다.
            // https://msdn.microsoft.com/en-us/library/cc848897(v=vs.85).aspx
            if (UTIL.isIE()){
                _saveAsWithExecCommand();
            }
            else{
                _saveAsWithDataURI();
            }
        }
    });

    function _saveAsWithMsSaveBlob(){

        // ie10 브라우저 이상
        blob = new Blob([fileData], { type: contentType });
        window.navigator.msSaveBlob(blob, _getFileName(fileName, type));
    }

    function _saveAsWithURL(){

        // window.URL 및 download 속성을 완벽히 지원하는 브라우저의 경우
        blob = new Blob([fileData], { type: contentType });

        let link = window.URL.createObjectURL(blob);

        let $a = $(document.createElement('a'));

        $a.prop('href', link);
        $a.css('display', 'none');
        $a.prop('download', _getFileName(fileName, type));

        $body.append($a);

        $a.get(0).click();

        $a.remove();
    }

    function _saveAsWithDataURI(){

        // Data URI Scheme 을 지원하는 브라우저들의 경우

        // 단점: 파일명을 지정할 수 없다(파일명이 Unknown 이라고 나온다(확장명도 없다))
        // 단, 다운받은 파일의 `포맷 형식(csv, xls 등)`에 맞춰 확장명을 붙어주면 해당 응용프로그램에서 실행할 수 있다.

        // ie8 ~ ie9 브라우저에서는 `data uri scheme`을 일부 contentType(text/plain 등)에 한해서만 지원하는 이슈가 존재한다.
        // https://msdn.microsoft.com/en-us/library/cc848897(v=vs.85).aspx

        $ifm.css('display', 'none');
        $body.append($ifm);

        $ifm.prop('src', 'data:' + contentType + ',' + encodeURIComponent(fileData));

        window.setTimeout(() => { $ifm.remove(); }, 3000);
    }

    function _saveAsWithExecCommand(){

        let separator = type === 'csv' ? 'sep=,\r\n' : '';

        $ifm.css('display', 'none');
        $body.append($ifm);

        let win = $ifm[0].contentWindow;
        let doc = win.document;

        doc.open('text/html', 'replace');
        doc.write(separator + fileData);
        doc.close();

        doc.execCommand('SaveAs', true, _getFileName(fileName, type));

        $ifm.remove();
    }

    return this;
}

/**
 * 엑셀 템플릿을 반환한다.
 *
 * @return {String} 엑셀 템플릿 데이터
 */
function _getExcelTemplate(){

    // ms office xml file format
    // https://en.wikipedia.org/wiki/Microsoft_Office_XML_formats#File_formats
    // https://blogs.msdn.microsoft.com/brian_jones/2005/06/27/introduction-to-excel-xml-part-1-creating-a-simple-table/
    // https://wiki.scn.sap.com/wiki/display/Snippets/XML+TAGS+simplifies+Excel+Download
    // https://www.sencha.com/forum/archive/index.php/t-14878.html
    // http://dazoom.tistory.com/69

    let tpl = [];
    let contentType = CONTENT_TYPE.excel;

    tpl.push(`<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">`);
    tpl.push(`<meta http-equiv="content-type" content="${contentType}" charset="utf-8">`);
    tpl.push(`<head>`);
    // ie9 이상
    tpl.push(`<!--[if gte mso 9]>`);
    tpl.push(`<xml>`);
    tpl.push(`<x:ExcelWorkbook>`);
    tpl.push(`<x:ExcelWorksheets>`);
    tpl.push(`<x:ExcelWorksheet>`);
    tpl.push(`<x:Name>{workSheetName}</x:Name>`);
    tpl.push(`<x:WorksheetOptions>`);
    tpl.push(`<x:DisplayGridlines/>`);
    tpl.push(`</x:WorksheetOptions>`);
    tpl.push(`</x:ExcelWorksheet>`);
    tpl.push(`</x:ExcelWorksheets>`);
    tpl.push(`</x:ExcelWorkbook>`);
    tpl.push(`</xml>`);
    tpl.push(`<![endif]-->`);
    tpl.push(`</head>`);
    tpl.push(`<body>`);
    tpl.push(`{elemText}`);
    tpl.push(`</body>`);
    tpl.push(`</html>`);

    return tpl.join('');
}

/**
 * 엑셀 템플릿을 변형 시킨다.
 *
 * @param {String} elemText - 엘리먼트 Text
 * @param {String} workSheetName - 워크시트명
 *
 * @return {String} 변형된 템플릿 데이터
 */
function _transformTemplate(elemText = '', workSheetName = ''){

    if (!_.isString(elemText) || !_.trim(elemText).length){
        CONSOLE.prop.throw('_transformTemplate', 'elemText', 'all');
    }

    if (!_.isString(workSheetName)){
        CONSOLE.prop.throw('_transformTemplate', 'workSheetName', 'all');
    }

    let tpl = _getExcelTemplate();

    let matchText = {
        workSheetName: workSheetName || 'Sheet1',
        elemText: elemText
    };

    return tpl.replace(/{(\w+)}/g, function (m, p) {
        return matchText[p];
    });
}

/**
 * 전체 파일명을 반환한다.
 *
 * @param {String} fileName - 파일명
 * @param {String} type - 파일 타입
 *
 * @return {String} 전체 파일명
 */
function _getFileName(fileName = '', type = 'csv') {

    if (!_.isString(fileName) || !_.trim(fileName).length){
        CONSOLE.prop.throw('_getFileName', 'fileName', 'all');
    }

    if (!_.isString(type) || !FILE_EXT[type]){
        CONSOLE.prop.throw('_getFileName', 'type', 'type');
    }

    let ext = FILE_EXT[type];

    return `${fileName}.${ext}`;
}

module.exports = EXPORTER;